// // This module implements a 1-bit wide 2-to-1 demultiplexer. Output F reflects the value of input A when S is low (0), and takes the value of input B when S is high (1).
module top_module(A,B,S,F);input A, B, S;
	output reg F;

	always @(A,B,S) begin
		if(S == 1) begin
			F = A;
		end
		else	begin
			F = B;
		end
	end

endmodule
